// pr-diff-fetcher.js
// N8N Code node — Phase 1: PR Risk Analyzer
// Receives a GitHub webhook payload and fetches the full PR diff via the GitHub API.
// Returns PR metadata + truncated diff text for downstream AI analysis.

const MAX_DIFF_CHARS = 12000;

// ── 1. Extract PR metadata from the webhook payload ──────────────────────────
const payload = $input.all()[0].json.body;
const pr = payload.pull_request;
const repo = payload.repository.full_name; // e.g. "owner/repo"

const prMeta = {
  pr_number: pr.number,
  pr_title: pr.title,
  pr_author: pr.user.login,
  pr_url: pr.html_url,
  repo_full_name: repo,
  additions: pr.additions,
  deletions: pr.deletions,
  changed_files: pr.changed_files,
};

// ── 2. Fetch the list of files changed in this PR ────────────────────────────
let filesData = [];

try {
  const url = `https://api.github.com/repos/${repo}/pulls/${pr.number}/files`;

  const response = await fetch(url, {
    headers: {
      Authorization: `Bearer ${$env.GITHUB_TOKEN}`,
      Accept: "application/vnd.github.v3+json",
    },
  });

  if (!response.ok) {
    throw new Error(
      `GitHub API responded ${response.status}: ${response.statusText}`,
    );
  }

  filesData = await response.json();
} catch (err) {
  // If the diff fetch fails, return metadata with a placeholder and log the error
  console.error("Failed to fetch PR diff:", err.message);

  return [
    {
      json: {
        ...prMeta,
        diff_text: "Diff unavailable",
        files_list: [],
      },
    },
  ];
}

// ── 3. Build per-file summaries and a combined diff string ───────────────────
const filesList = [];
let combinedDiff = "";

for (const file of filesData) {
  filesList.push(file.filename);

  // Each file section: header line + patch (the actual diff hunks)
  const section = [
    `--- ${file.filename} (${file.status}) +${file.additions} -${file.deletions}`,
    file.patch || "(binary or empty)",
    "", // blank line separator
  ].join("\n");

  combinedDiff += section;
}

// ── 4. Truncate the combined diff to fit within the AI context budget ────────
let diffText = combinedDiff;
if (diffText.length > MAX_DIFF_CHARS) {
  diffText = diffText.slice(0, MAX_DIFF_CHARS) + "\n... [diff truncated]";
}

// ── 5. Return a single item with PR metadata + diff ──────────────────────────
return [
  {
    json: {
      ...prMeta,
      diff_text: diffText,
      files_list: filesList,
    },
  },
];

// risk-prompt-builder.js
// N8N Code node — Phase 1: PR Risk Analyzer
// Builds structured system + user prompts for AI-based PR risk classification.
// Receives the output of pr-diff-fetcher.js and passes everything downstream.

// ── 1. Grab diff-fetcher output ──────────────────────────────────────────────
const input = $input.all()[0].json;

// ── 2. System instruction ────────────────────────────────────────────────────
const system_prompt =
  "You are a senior software engineer reviewing pull requests. " +
  "Classify the risk level and provide a brief summary. " +
  "Respond ONLY with valid JSON, no markdown fences.";

// ── 3. Build the user message ────────────────────────────────────────────────
const user_prompt = `## Pull Request for Review

**Title:** ${input.pr_title}
**Author:** ${input.pr_author}
**Files changed:** ${input.changed_files}
**Lines added:** ${input.additions}
**Lines removed:** ${input.deletions}

### Files Changed
${input.files_list.map((f) => `- ${f}`).join("\n")}

### Diff
\`\`\`
${input.diff_text}
\`\`\`

## Classification Task

Classify this PR into exactly one risk level using these criteria:

- **low** — documentation, tests, config tweaks, typo fixes
- **medium** — new features with tests, refactors of non-critical paths
- **high** — changes to auth, payments, database schemas, core business logic, or PRs with no tests
- **critical** — security-related changes, breaking API changes, infrastructure / deployment changes

Respond with **only** a JSON object (no markdown, no extra text) containing exactly these fields:

{
  "risk_level": "low|medium|high|critical",
  "summary": "2-3 sentence summary of what this PR does and why it has this risk level",
  "key_concerns": ["array of specific concerns if medium/high/critical, empty array for low"],
  "suggested_reviewers": ["areas of expertise needed, e.g. 'database', 'security', 'frontend'"]
}`;

// ── 4. Pass through PR metadata so downstream nodes can store it ─────────────
const pr_metadata = {
  pr_number: input.pr_number,
  pr_title: input.pr_title,
  pr_author: input.pr_author,
  pr_url: input.pr_url,
  repo_full_name: input.repo_full_name,
  additions: input.additions,
  deletions: input.deletions,
  changed_files: input.changed_files,
  diff_text: input.diff_text,
  files_list: input.files_list,
};

// ── 5. Return single item ────────────────────────────────────────────────────
return [
  {
    json: {
      system_prompt,
      user_prompt,
      pr_metadata,
    },
  },
];

// Format Slack Message — workflow context
// Input arrives from Merge node: Anthropic API response fields + prompt builder fields combined

const input = $input.all()[0].json;
const meta = input.pr_metadata;

// Extract AI text from Anthropic response format
let aiText = "";
try {
  aiText = input.content[0].text;
} catch (e) {
  // content may be missing if API call structure differs
}

// Parse AI response (tolerant of markdown fences)
let classification;
try {
  let raw = aiText;
  raw = raw.replace(/```(?:json)?\s*/gi, "").replace(/```/g, "").trim();
  classification = JSON.parse(raw);
} catch (err) {
  console.error("Failed to parse AI response:", err.message);
  return [{
    json: {
      slack_blocks: [
        { type: "header", text: { type: "plain_text", text: "⚠️ PR #" + meta.pr_number + ": Classification Failed", emoji: true } },
        { type: "section", text: { type: "mrkdwn", text: "Automatic classification failed — *manual review needed*." } },
        { type: "actions", elements: [{ type: "button", text: { type: "plain_text", text: "View PR", emoji: true }, url: meta.pr_url, style: "danger" }] }
      ],
      slack_text: "⚠️ PR #" + meta.pr_number + " (" + meta.pr_title + ") — classification failed, manual review needed: " + meta.pr_url,
      risk_level: "unknown",
      pr_number: meta.pr_number, pr_title: meta.pr_title, pr_author: meta.pr_author,
      pr_url: meta.pr_url, repo_full_name: meta.repo_full_name,
      additions: meta.additions, deletions: meta.deletions, changed_files: meta.changed_files
    }
  }];
}

const riskMap = {
  low:      { emoji: "🟢", color: "#36a64f" },
  medium:   { emoji: "🟡", color: "#daa520" },
  high:     { emoji: "🟠", color: "#ff8c00" },
  critical: { emoji: "🔴", color: "#dc3545" }
};

const level = classification.risk_level ?? "medium";
const { emoji, color } = riskMap[level] ?? riskMap.medium;

const blocks = [];

blocks.push({ type: "header", text: { type: "plain_text", text: emoji + " PR #" + meta.pr_number + ": " + meta.pr_title, emoji: true } });
blocks.push({ type: "section", text: { type: "mrkdwn", text: classification.summary } });
blocks.push({ type: "section", fields: [
  { type: "mrkdwn", text: "*Author:*\n" + meta.pr_author },
  { type: "mrkdwn", text: "*Risk Level:*\n" + emoji + " " + level.toUpperCase() },
  { type: "mrkdwn", text: "*Files Changed:*\n" + meta.changed_files },
  { type: "mrkdwn", text: "*Lines:*\n+" + meta.additions + " / -" + meta.deletions }
] });

const concerns = classification.key_concerns ?? [];
if (concerns.length > 0) {
  blocks.push({ type: "section", text: { type: "mrkdwn", text: "*Key Concerns:*\n" + concerns.map(function(c) { return "• " + c; }).join("\n") } });
}

const reviewers = classification.suggested_reviewers ?? [];
if (reviewers.length > 0) {
  blocks.push({ type: "context", elements: [{ type: "mrkdwn", text: "👀 *Suggested expertise:* " + reviewers.join(", ") }] });
}

blocks.push({ type: "divider" });
blocks.push({ type: "actions", elements: [{
  type: "button",
  text: { type: "plain_text", text: "View PR", emoji: true },
  url: meta.pr_url,
  style: (level === "critical" || level === "high") ? "danger" : "primary"
}] });

const slack_text = emoji + " PR #" + meta.pr_number + " (" + meta.pr_title + ") — Risk: " + level.toUpperCase() + " — " + meta.pr_url;

return [{
  json: {
    slack_blocks: blocks,
    slack_text: slack_text,
    slack_color: color,
    risk_level: level,
    risk_summary: classification.summary,
    key_concerns: concerns,
    suggested_reviewers: reviewers,
    raw_ai_response: classification,
    pr_number: meta.pr_number,
    pr_title: meta.pr_title,
    pr_author: meta.pr_author,
    pr_url: meta.pr_url,
    repo_full_name: meta.repo_full_name,
    additions: meta.additions,
    deletions: meta.deletions,
    changed_files: meta.changed_files,
    ai_model_used: input.model ?? "unknown"
  }
}];

// Error notification for Slack
const error = $input.all()[0].json;
const msg = error.execution?.error?.message ?? "Unknown error";
const executionId = error.execution?.id ?? "N/A";

return [{
  json: {
    text: "⚠️ *ShipWatch: PR analysis failed*\nExecution: " + executionId + "\nError: " + msg
  }
}];
